import { useEffect, useState } from "react";
import API from "../services/api";

function Tasks() {
  const [tasks, setTasks] = useState([]);
  const [title, setTitle] = useState("");
  const [dueDate, setDueDate] = useState("");


  const fetchTasks = async () => {
    const res = await API.get("/tasks");
    setTasks(res.data);
  };

  const addTask = async (e) => {
    e.preventDefault();
   await API.post("/tasks", { title, dueDate });
    setTitle("");
    fetchTasks();
  };

  const completeTask = async (id) => {
    await API.put(`/tasks/${id}`, { status: "completed" });
    fetchTasks();
  };

  const deleteTask = async (id) => {
    await API.delete(`/tasks/${id}`);
    fetchTasks();
  };

  useEffect(() => {
    fetchTasks();
  }, []);

  const getDeadlineColor = (dueDate) => {
  if (!dueDate) return "#ffffff";

  const today = new Date();
  const deadline = new Date(dueDate);
  const diffDays =
    (deadline - today) / (1000 * 60 * 60 * 24);

  if (diffDays < 0) return "#ffe5e5";       // overdue
  if (diffDays <= 3) return "#fff4cc";      // due soon
  return "#e6fffa";                         // future
};


  return (
    <div>
       <button
      style={{
        position: "absolute",
        top: "20px",
        right: "20px",
        background: "#dc3545",
        color: "white",
        border: "none",
        padding: "8px 14px",
        borderRadius: "6px",
        cursor: "pointer",
      }}
      onClick={() => {
        localStorage.removeItem("token");
        window.location.reload();
      }}
    >
      Logout
    </button>

      <h3>My Tasks</h3>

      <form onSubmit={addTask} className="task-input">
  <input
    placeholder="New task title"
    value={title}
    onChange={(e) => setTitle(e.target.value)}
    required
  />

  <input
    type="date"
    value={dueDate}
    onChange={(e) => setDueDate(e.target.value)}
  />

  <button type="submit">Add</button>
</form>

      <div>
  {tasks.map((task) => (
    <div
  className="task-item"
  key={task._id}
  style={{ backgroundColor: getDeadlineColor(task.dueDate) }}
>

      <div>
        <strong>{task.title}</strong>
        <div>Status: {task.status}</div>
        <div>
          Deadline:{" "}
          {task.dueDate
            ? new Date(task.dueDate).toLocaleDateString()
            : "Not set"}
        </div>
      </div>

      <div className="task-buttons">
        {task.status !== "completed" && (
          <button onClick={() => completeTask(task._id)}>
            Complete
          </button>
        )}
        <button onClick={() => deleteTask(task._id)}>
          Delete
        </button>
      </div>
    </div>
  ))}
</div>

    </div>
  );
}

export default Tasks;
